int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long M, Q, N, D;
        scanf("%lld %lld %lld %lld", &M, &Q, &N, &D);
        long long A[D + 1];
        for (int i = 0; i <= D; i++) {
            scanf("%lld", &A[i]);
        }
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            long long P = 0;
            for (int j = 0; j <= D; j++) {
                long long C = 1;
                for (int k = 0; k <= D; k++) {
                    if (k != j) {
                        C = (C * (i - k)) % M;
                        C = (C * modInverse(j - k, M)) % M;
                    }
                }
                P = (P + C * A[j]) % M;
            }
            sum = (sum + P * power(Q, i, M)) % M;
        }
        printf("%lld\n", sum);
    }
    return 0;
}
long long power(long long a, long long b, long long M) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % M;
        a = (a * a) % M;
        b >>= 1;
    }
    return res;
}
long long modInverse(long long a, long long M) {
    long long m0 = M;
    long long y = 0, x = 1;
    if (M == 1) return 0;
    while (a > 1) {
        long long q = a / M;
        long long t = M;
        M = a % M; a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0) x += m0;
    return x;
}

