import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long M = sc.nextLong();
            long Q = sc.nextLong();
            long N = sc.nextLong();
            long D = sc.nextLong();
            long[] A = new long[(int)D + 1];
            for (int i = 0; i <= D; i++) {
                A[i] = sc.nextLong();
            }
            long sum = 0;
            for (int i = 0; i < N; i++) {
                long P = 0;
                for (int j = 0; j <= D; j++) {
                    long C = 1;
                    for (int k = 0; k <= D; k++) {
                        if (k != j) {
                            C = (C * (i - k)) % M;
                            C = (C * modInverse(j - k, M)) % M;
                        }
                    }
                    P = (P + C * A[j]) % M;
                }
                sum = (sum + P * power(Q, i, M)) % M;
            }
            System.out.println(sum);
        }
    }
    public static long power(long a, long b, long M) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % M;
            a = (a * a) % M;
            b >>= 1;
        }
        return res;
    }
    public static long modInverse(long a, long M) {
        long m0 = M;
        long y = 0, x = 1;
        if (M == 1) return 0;
        while (a > 1) {
            long q = a / M;
            long t = M;
            M = a % M; a = t;
            t = y;
            y = x - q * y;
            x = t;
        }
        if (x < 0) x += m0;
        return x;
    }
}

